import React from 'react';
import './App.css';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import LinkCard from './components/LinkCard';

const App: React.FC = () => {
  return (
    <Router>
      <div className="App">
        <h1>Link Archive</h1>
        <Switch>
          <Route path="/" exact>
            <div>
              {/* Main content can go here */}
            </div>
          </Route>
          <Route path="/link/:id" component={LinkCard} />
        </Switch>
      </div>
    </Router>
  );
};

export default App;
